  ],
  "questionProse": [
    "इस स्क्रिप्ट में `:` का काम क्या है?"
  ],
  "explanationProse": [
    "`${var:offset}` सिंटैक्स `offset` इंडेक्स से शुरू होकर स्ट्रिंग का हिस्सा (सबस्ट्रिंग) निकालता है। यहाँ आउटपुट होगा:",
    "किसी विशिष्ट लंबाई की सबस्ट्रिंग निकालने के लिए `${var:offset:length}` का उपयोग करें।\n\n    स्ट्रिंग के अंत से निकालने के लिए `${var: -offset}` का उपयोग करें। (ध्यान दें कि `-` से पहले स्पेस है!)"
  ]
}
